content.text:
---
import '../styles/global.css';

interface Props {
  title?: string;
  description?: string;
}

const {
  title = 'incomplete.fun',
  description = 'A collection of fun, incomplete things.',
} = Astro.props;
---

<!doctype html>
<html lang="en">
  <head>
    <meta charset="utf-8" />
    <link rel="icon" type="image/svg+xml" href="/favicon.svg" />
    <link rel="icon" href="/favicon.ico" />
    <meta name="viewport" content="width=device-width" />
    <meta name="description" content={description} />
    <title>{title}</title>
  </head>
  <body>
    <slot />
  </body>
</html>

---
import BaseLayout from './BaseLayout.astro';

interface Props {
  name: string;
  back?: boolean;
  wide?: boolean;
}

const { name, back = false, wide = false } = Astro.props;
const title = name === 'incomplete.fun' ? name : `${name} - incomplete.fun`;
---

<BaseLayout title={title}>
  <div class="app-shell">
    <div class="topbar">
      {back && <a class="back-link" href="/" aria-label="Back to home">←</a>}
      <span><strong>{name}</strong></span>
    </div>
    <main class={wide ? 'page page-wide' : 'page'}>
      <slot />
    </main>
  </div>
</BaseLayout>

:root {
  color-scheme: light dark;
  --bg: #fbfbf9;
  --fg: #181817;
  --muted: #77736b;
  --line: #dedbd2;
  --accent: currentColor;
  --border: var(--line);
  --mono: inherit;
  --space: clamp(1rem, 4vw, 2.5rem);
  --measure: 38rem;
  font-family: ui-monospace, "SFMono-Regular", Menlo, Consolas, monospace;
}

@media (prefers-color-scheme: dark) {
  :root {
    --bg: #10100f;
    --fg: #eeeeea;
    --muted: #98948b;
    --line: #2d2b28;
  }
}

* { box-sizing: border-box; }

body {
  margin: 0;
  background: var(--bg);
  color: var(--fg);
  font-size: 15px;
  line-height: 1.65;
}

a {
  color: inherit;
  text-decoration: underline;
  text-decoration-color: var(--line);
  text-underline-offset: .25em;
}

a:hover { text-decoration-color: currentColor; }

h1, h2, h3, p, ul, ol { margin: 0 0 1rem; }

h1, h2, h3, strong { font-weight: 600; }

ul, ol { padding-left: 1.25rem; }

code {
  padding: .1em .3em;
  border: 1px solid var(--line);
  border-radius: 3px;
}

.app-shell, .canvas-app {
  min-height: 100dvh;
  background: var(--bg);
}

.app-shell { display: grid; grid-template-rows: auto 1fr; }
.canvas-app { display: flex; flex-direction: column; }

.topbar {
  display: flex;
  align-items: center;
  gap: 1rem;
  min-height: 3.25rem;
  padding: .75rem var(--space);
  border-bottom: 1px solid var(--line);
  flex-wrap: wrap;
}

.back-link {
  color: var(--muted);
  text-decoration: none;
}

.page {
  width: min(100%, var(--measure));
  margin: 0 auto;
  padding: calc(var(--space) * 1.4) var(--space);
}

.page-wide { --measure: 72rem; }

.home-intro { color: var(--muted); }

.home-links {
  list-style: none;
  padding: 0;
}

.home-links a {
  display: inline-block;
  padding: .15rem 0;
}

.canvas-stage {
  position: relative;
  flex: 1;
  overflow: hidden;
}

button, input {
  font: inherit;
  color: inherit;
}

.toolbar-button,
.metric-button {
  background: transparent;
  border: 1px solid var(--line);
  border-radius: 999px;
  padding: .15rem .7rem;
  cursor: pointer;
}

.toolbar-button:hover,
.metric-button:hover,
.metric-button.is-active {
  background: var(--fg);
  border-color: var(--fg);
  color: var(--bg);
}

.control-label {
  display: inline-flex;
  align-items: center;
  gap: .4rem;
  color: var(--muted);
}

input[type="number"] {
  width: 3.5rem;
  background: transparent;
  border: 1px solid var(--line);
  border-radius: 4px;
  padding: .1rem .35rem;
}

input[type="color"] {
  width: 2rem;
  height: 1.4rem;
  padding: 0;
  border: 1px solid var(--line);
  background: transparent;
}

input[type="checkbox"],
input[type="range"] {
  accent-color: var(--fg);
}

--- src/pages/cellular.astro
---
import PageLayout from '../layouts/PageLayout.astro';
---

<PageLayout name="cellular automata lab" back wide>
  <p class="cellular-intro">Explore simple local rules by editing seed states, stepping time forward, and watching compact histories accumulate.</p>

  <section class="cellular-lab" id="cellular-app">
    <article class="cellular-card">
      <div class="cellular-card-head">
        <div>
          <h2>1D elementary rules</h2>
          <p>Each cell looks at its left, center, and right neighbors. The 8-bit rule number decides the next row.</p>
        </div>
        <div class="cellular-toolbar" aria-label="1D controls">
          <label>rule <input id="ca1-rule" type="number" min="0" max="255" value="30" /></label>
          <button class="toolbar-button" id="ca1-step" type="button">step</button>
          <button class="toolbar-button" id="ca1-play" type="button">play</button>
          <button class="toolbar-button" id="ca1-single" type="button">single seed</button>
          <button class="toolbar-button" id="ca1-random" type="button">random</button>
          <button class="toolbar-button" id="ca1-clear" type="button">clear</button>
        </div>
      </div>

      <div class="cellular-rule" id="ca1-rule-table" aria-live="polite"></div>
      <div class="cellular-canvas-wrap">
        <canvas id="ca1-canvas" width="960" height="560" aria-label="1D automaton history"></canvas>
      </div>
      <p class="cellular-hint">Click the top row to toggle cells and restart the visible history from that edited seed.</p>
    </article>

    <article class="cellular-card">
      <div class="cellular-card-head">
        <div>
          <h2>2D outer-totalistic rules</h2>
          <p>Birth/survival rules use the count of live neighbors around each square. Start with Conway's Life, then try variants.</p>
        </div>
        <div class="cellular-toolbar" aria-label="2D controls">
          <label>
            rule
            <select id="ca2-rule">
              <option value="life">Life B3/S23</option>
              <option value="highlife">HighLife B36/S23</option>
              <option value="seeds">Seeds B2/S</option>
              <option value="daynight">Day &amp; Night B3678/S34678</option>
              <option value="majority">Majority B5678/S45678</option>
            </select>
          </label>
          <button class="toolbar-button" id="ca2-step" type="button">step</button>
          <button class="toolbar-button" id="ca2-play" type="button">play</button>
          <button class="toolbar-button" id="ca2-random" type="button">random</button>
          <button class="toolbar-button" id="ca2-clear" type="button">clear</button>
        </div>
      </div>

      <div class="cellular-2d-grid">
        <div>
          <div class="cellular-canvas-wrap">
            <canvas id="ca2-canvas" width="768" height="480" aria-label="2D automaton grid"></canvas>
          </div>
          <p class="cellular-hint">Click or drag on the grid to draw live cells. Edges wrap like a torus.</p>
        </div>
        <aside class="cellular-history-panel">
          <h3>history</h3>
          <canvas id="ca2-history" width="280" height="280" aria-label="2D automaton population history"></canvas>
          <div class="cellular-stats" id="ca2-stats" aria-live="polite"></div>
        </aside>
      </div>
    </article>
  </section>
</PageLayout>

<style>
  .cellular-intro,
  .cellular-hint,
  .cellular-card p,
  .cellular-stats { color: var(--muted); }

  .cellular-lab { display: grid; gap: 1rem; }

  .cellular-card {
    border: 1px solid var(--line);
    padding: 1rem;
    display: grid;
    gap: 1rem;
  }

  .cellular-card-head {
    display: grid;
    grid-template-columns: minmax(0, 1fr) auto;
    gap: 1rem;
    align-items: start;
  }

  .cellular-card h2,
  .cellular-card h3 { font-size: 1rem; margin-bottom: 0.25rem; }

  .cellular-toolbar {
    display: flex;
    flex-wrap: wrap;
    justify-content: end;
    gap: 0.45rem;
    align-items: center;
  }

  .cellular-toolbar label {
    display: inline-flex;
    align-items: center;
    gap: 0.35rem;
    color: var(--muted);
  }

  .cellular-toolbar input,
  .cellular-toolbar select {
    background: transparent;
    border: 1px solid var(--line);
    border-radius: 4px;
    color: var(--fg);
    padding: 0.15rem 0.35rem;
    font: inherit;
  }

  .cellular-toolbar input { width: 4.25rem; }

  .cellular-rule {
    display: grid;
    grid-template-columns: repeat(8, minmax(4.25rem, 1fr));
    gap: 0.35rem;
    overflow-x: auto;
    font-size: 0.78rem;
  }

  .rule-chip {
    border: 1px solid var(--line);
    padding: 0.35rem;
    display: grid;
    gap: 0.25rem;
    justify-items: center;
  }

  .rule-cells { display: grid; grid-template-columns: repeat(3, 0.7rem); gap: 0.12rem; }
  .rule-cell, .rule-out { width: 0.7rem; height: 0.7rem; border: 1px solid var(--line); }
  .rule-out { width: 1rem; }
  .is-alive { background: var(--fg); }

  .cellular-canvas-wrap {
    border: 1px solid var(--line);
    overflow: auto;
    background: color-mix(in srgb, var(--bg) 94%, var(--fg));
  }

  .cellular-canvas-wrap canvas {
    display: block;
    width: 100%;
    height: auto;
    image-rendering: pixelated;
    cursor: crosshair;
  }

  .cellular-2d-grid {
    display: grid;
    grid-template-columns: minmax(0, 1fr) minmax(16rem, 18rem);
    gap: 1rem;
  }

  .cellular-history-panel {
    border: 1px solid var(--line);
    padding: 0.75rem;
  }

  #ca2-history {
    width: 100%;
    height: auto;
    border: 1px solid var(--line);
    image-rendering: pixelated;
    background: color-mix(in srgb, var(--bg) 94%, var(--fg));
  }

  .cellular-stats { font-size: 0.85rem; margin-top: 0.75rem; }

  @media (max-width: 56rem) {
    .cellular-card-head,
    .cellular-2d-grid { grid-template-columns: 1fr; }
    .cellular-toolbar { justify-content: start; }
    .cellular-rule { grid-template-columns: repeat(8, 4.25rem); }
  }
</style>

<script>
  import '../scripts/cellular.ts';
</script>
--- src/pages/complex.astro
---
import BaseLayout from '../layouts/BaseLayout.astro';
---

<BaseLayout title="complex dynamics - incomplete.fun">
  <div class="canvas-app" id="complex-app">
    <div class="topbar" id="complex-toolbar">
      <a class="back-link" href="/" aria-label="Back to home">←</a>
      <span><strong>complex dynamics</strong></span>

      <button class="mode-button is-active" id="complex-mandelbrot" type="button">mandelbrot</button>
      <button class="mode-button" id="complex-julia" type="button">julia</button>

      <label class="control-label">
        c=
        <input id="complex-c-real" type="number" step="0.001" value="-0.800" />
        <input id="complex-c-imag" type="number" step="0.001" value="0.156" />
      </label>

      <label class="control-label">
        iter
        <input id="complex-iterations" type="range" min="40" max="600" step="10" value="180" />
        <span id="complex-iteration-value">180</span>
      </label>

      <button class="toolbar-button" id="complex-reset" type="button">reset</button>
      <span class="complex-help">wheel zoom · drag pan · click Mandelbrot to pick Julia c</span>
    </div>

    <div id="complex-readout">
      <span id="complex-coords">z = 0 + 0i</span>
      <span id="complex-status">ready</span>
    </div>

    <div class="canvas-stage" id="complex-stage">
      <canvas id="complex-canvas"></canvas>
      <canvas id="complex-orbit"></canvas>
    </div>
  </div>
</BaseLayout>

<style>
  .mode-button {
    background: transparent;
    border: 1px solid var(--line);
    border-radius: 999px;
    padding: .15rem .7rem;
    cursor: pointer;
  }

  .mode-button:hover,
  .mode-button.is-active {
    background: var(--fg);
    border-color: var(--fg);
    color: var(--bg);
  }

  #complex-c-real,
  #complex-c-imag {
    width: 5.5rem;
  }

  #complex-iterations {
    width: 6rem;
  }

  #complex-iteration-value {
    min-width: 2.25rem;
    color: var(--muted);
    font-variant-numeric: tabular-nums;
  }

  .complex-help {
    margin-left: auto;
    color: var(--muted);
    font-size: .78rem;
  }

  #complex-readout {
    display: flex;
    justify-content: space-between;
    gap: 1rem;
    padding: .35rem var(--space);
    border-bottom: 1px solid var(--line);
    color: var(--muted);
    font-size: .78rem;
    font-variant-numeric: tabular-nums;
  }

  #complex-status {
    text-align: right;
  }

  #complex-stage {
    cursor: crosshair;
    touch-action: none;
  }

  #complex-canvas,
  #complex-orbit {
    position: absolute;
    inset: 0;
    display: block;
    width: 100%;
    height: 100%;
  }

  #complex-orbit {
    pointer-events: none;
  }
</style>

<script>
  import '../scripts/complex.ts';
</script>
--- src/pages/continued-fractions.astro
---
import PageLayout from '../layouts/PageLayout.astro';
---

<PageLayout name="continued fraction calculator" back wide>
  <p class="cf-intro">Expand rationals and quadratic irrationals into continued fractions. The page shows the term list, a nested fraction preview, convergents, approximation errors, and the geometry behind the approximation.</p>

  <section class="cf-grid" id="cf-app">
    <form class="cf-card" id="cf-form">
      <h2>number</h2>
      <label>kind
        <select id="cf-kind">
          <option value="rational">rational p/q</option>
          <option value="quadratic">quadratic (a + b√d) / c</option>
        </select>
      </label>
      <div class="cf-rational-fields">
        <label>p <input id="cf-p" type="number" step="1" value="355" /></label>
        <label>q <input id="cf-q" type="number" step="1" value="113" /></label>
      </div>
      <div class="cf-quadratic-fields" hidden>
        <label>a <input id="cf-a" type="number" step="1" value="1" /></label>
        <label>b <input id="cf-b" type="number" step="1" value="1" /></label>
        <label>d <input id="cf-d" type="number" step="1" value="5" /></label>
        <label>c <input id="cf-c" type="number" step="1" value="2" /></label>
      </div>
      <label>terms <input id="cf-terms" type="number" min="1" max="80" value="24" /></label>
      <button class="toolbar-button" type="submit">expand</button>
      <div class="cf-output" id="cf-summary"></div>
    </form>

    <article class="cf-card">
      <h2>how to read it</h2>
      <div class="cf-explain">
        <p><strong>continued fraction:</strong> <code>[a₀; a₁, a₂, …]</code> means <code>a₀ + 1/(a₁ + 1/(a₂ + …))</code>.</p>
        <p><strong>convergent pₙ/qₙ:</strong> truncate after <code>aₙ</code>. These fractions are often the best small-denominator approximations.</p>
        <p><strong>error plot:</strong> shows correct decimal digits, <code>−log₁₀(|x − pₙ/qₙ|)</code>. Higher means better.</p>
      </div>
    </article>

    <article class="cf-card cf-wide">
      <h2>expanded form</h2>
      <div class="cf-output cf-expanded" id="cf-expanded"></div>
    </article>

    <article class="cf-card cf-wide">
      <h2>convergents</h2>
      <p class="cf-intro">Each row truncates the continued fraction one term later. Watch the denominator grow and the error usually drop sharply.</p>
      <div class="cf-table-wrap"><table id="cf-table"></table></div>
    </article>

    <article class="cf-card cf-wide">
      <h2>error plot</h2>
      <p class="cf-intro">A rising point means the convergent gained decimal accuracy. Flat or low points are normal for early terms.</p>
      <svg id="cf-error-plot" viewBox="0 0 900 220" role="img" aria-label="Convergent error plot"></svg>
    </article>

    <article class="cf-card cf-wide">
      <h2>geometric intervals</h2>
      <p class="cf-intro">Even and odd convergents approach from opposite sides. Each line spans two consecutive convergents; the target is trapped inside the shrinking intervals.</p>
      <svg id="cf-intervals" viewBox="0 0 900 260" role="img" aria-label="Continued fraction nested intervals"></svg>
    </article>
  </section>
</PageLayout>

<style>
  .cf-intro { color: var(--muted); }
  .cf-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(min(100%, 24rem), 1fr)); gap: 1rem; }
  .cf-wide { grid-column: 1 / -1; }
  .cf-card { border: 1px solid var(--line); padding: 1rem; display: grid; gap: .75rem; }
  .cf-card h2 { font-size: 1rem; margin: 0; }
  .cf-card label, .cf-rational-fields, .cf-quadratic-fields { display: grid; gap: .3rem; color: var(--muted); }
  .cf-rational-fields, .cf-quadratic-fields { grid-template-columns: repeat(auto-fit, minmax(5rem, 1fr)); }
  .cf-card input, .cf-card select { width: 100%; background: transparent; color: var(--fg); border: 1px solid var(--line); border-radius: 4px; padding: .35rem .45rem; font: inherit; }
  .cf-output, .cf-table-wrap { overflow-x: auto; }
  .cf-explain { display: grid; gap: .6rem; color: var(--muted); }
  .cf-explain p { margin: 0; }
  .cf-expanded { font-size: 1.05rem; line-height: 2; }
  .cf-nested { display: inline-block; white-space: nowrap; }
  .cf-frac { display: inline-grid; grid-template-rows: auto auto; vertical-align: middle; text-align: center; margin: 0 .08rem; }
  .cf-frac > span:first-child { border-bottom: 1px solid currentColor; padding: 0 .25rem; }
  .cf-frac > span:last-child { padding: 0 .25rem; }
  .cf-pill { display: inline-block; border: 1px solid var(--line); border-radius: 999px; padding: .05rem .45rem; margin: .1rem; }
  #cf-table { width: 100%; border-collapse: collapse; font-variant-numeric: tabular-nums; }
  #cf-table th, #cf-table td { border-top: 1px solid var(--line); padding: .35rem .5rem; text-align: right; }
  #cf-table th:first-child, #cf-table td:first-child { text-align: left; }
  #cf-error-plot, #cf-intervals { width: 100%; height: auto; border: 1px solid var(--line); }
</style>

<style is:global>
  .cf-axis, .cf-grid-line { stroke: var(--line); }
  .cf-grid-line { opacity: .55; }
  .cf-mark { fill: var(--fg); }
  .cf-muted { fill: var(--muted); font-size: 12px; }
  .cf-line { stroke: var(--fg); fill: none; stroke-width: 2; }
</style>

<script>
  import '../scripts/continued-fractions.ts';
</script>
--- src/pages/groups.astro
---
import PageLayout from '../layouts/PageLayout.astro';
---

<PageLayout name="finite group explorer" back wide>
  <p class="group-intro">Explore Cayley tables, element orders, subgroups, normal subgroups, centers, conjugacy classes, and quotients for small finite groups.</p>

  <section class="group-panel" id="group-app">
    <div class="group-controls">
      <label>
        group
        <select id="group-select">
          <option value="C2">cyclic C₂</option>
          <option value="C3">cyclic C₃</option>
          <option value="C4">cyclic C₄</option>
          <option value="C5">cyclic C₅</option>
          <option value="C6">cyclic C₆</option>
          <option value="C7">cyclic C₇</option>
          <option value="C8">cyclic C₈</option>
          <option value="V4">klein four V₄</option>
          <option value="D3">dihedral D₃</option>
          <option value="D4" selected>dihedral D₄</option>
          <option value="D5">dihedral D₅</option>
          <option value="D6">dihedral D₆</option>
          <option value="S3">symmetric S₃</option>
          <option value="Q8">quaternion Q₈</option>
        </select>
      </label>
      <label>
        quotient by normal subgroup
        <select id="normal-select"></select>
      </label>
    </div>

    <div class="group-summary" id="group-summary"></div>

    <div class="group-grid">
      <article class="group-card group-wide">
        <h2>cayley table</h2>
        <div class="group-table-wrap" id="cayley-table"></div>
      </article>

      <article class="group-card">
        <h2>element orders</h2>
        <div id="element-orders"></div>
      </article>

      <article class="group-card">
        <h2>center</h2>
        <div id="center-output"></div>
      </article>

      <article class="group-card">
        <h2>conjugacy classes</h2>
        <div id="conjugacy-output"></div>
      </article>

      <article class="group-card group-wide">
        <h2>subgroups</h2>
        <div id="subgroups-output"></div>
      </article>

      <article class="group-card group-wide">
        <h2>quotient</h2>
        <div id="quotient-output"></div>
      </article>
    </div>
  </section>
</PageLayout>

<style>
  .group-intro {
    color: var(--muted);
  }

  .group-panel {
    display: grid;
    gap: 1rem;
  }

  .group-controls {
    display: flex;
    gap: 1rem;
    flex-wrap: wrap;
    align-items: end;
  }

  .group-controls label {
    display: grid;
    gap: 0.25rem;
    color: var(--muted);
  }

  .group-controls select {
    min-width: 14rem;
    background: var(--bg);
    color: var(--fg);
    border: 1px solid var(--line);
    border-radius: 4px;
    padding: 0.35rem 0.45rem;
    font: inherit;
  }

  .group-summary,
  .group-card {
    border: 1px solid var(--line);
    padding: 1rem;
  }

  .group-summary {
    color: var(--muted);
  }

  .group-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(min(100%, 22rem), 1fr));
    gap: 1rem;
  }

  .group-wide {
    grid-column: 1 / -1;
  }

  .group-card h2 {
    font-size: 1rem;
    margin-bottom: 0.75rem;
  }

  .group-table-wrap {
    overflow: auto;
  }

  .group-table {
    width: 100%;
    min-width: max-content;
    border-collapse: collapse;
    font-size: 0.85rem;
    font-variant-numeric: tabular-nums;
  }

  .group-table th,
  .group-table td {
    border: 1px solid var(--line);
    padding: 0.25rem 0.45rem;
    text-align: center;
    white-space: nowrap;
  }

  .group-table th {
    font-weight: 600;
  }

  .group-list {
    display: grid;
    gap: 0.35rem;
    margin: 0;
    padding-left: 1.25rem;
  }

  .group-muted {
    color: var(--muted);
  }

  .group-chip {
