        <button class="toolbar-button" id="knot-r2" type="button" title="Remove one visible crossing by reversing the strand between its segments">remove one crossing</button>
        <button class="toolbar-button" id="knot-clear" type="button">clear</button>
        <span class="knot-note">drag to draw · click crossings to flip over/under</span>
      </div>
      <div class="knot-stage">
        <canvas id="knot-canvas" width="1000" height="560"></canvas>
